/* =========================
   NORMAL QUIZ LOGIC (UNCHANGED CORE)
========================= */

export function selectNextQuestion(pool, mode) {
  if (!pool || pool.length === 0) return null

  if (mode === 'new') {
    return pool.find(q => !q.seen) || pool[0]
  }

  if (mode === 'wrong') {
    return pool.find(q => q.last_correct === false) || pool[0]
  }

  return pool[Math.floor(Math.random() * pool.length)]
}

/* =========================
   REMEDIATION ENGINE
========================= */

// Get concept tag safely
export function getQuestionConceptTag(q) {
  return (
    q.concept_tag ||
    `${q.subject}|${q.topic}|${q.subtopic}`.toLowerCase()
  )
}

// Build remediation queue
export async function buildRemediationQueue({
  question,
  db
}) {
  const concept = getQuestionConceptTag(question)

  // 1. Same question variants
  const direct = await db.getVariantsByParent(question.id)

  if (direct && direct.length > 0) {
    return shuffle(direct)
  }

  // 2. Concept-level variants
  const conceptVariants = await db.getVariantsByConcept(concept)

  if (conceptVariants && conceptVariants.length > 0) {
    return shuffle(conceptVariants)
  }

  // 3. Fallback → empty (AI will fill)
  return []
}

/* =========================
   XP SYSTEM
========================= */

export function calcXP(correct, difficulty = 1) {
  if (!correct) return 0
  return 10 * difficulty
}

export function calcRemediationXP() {
  return 5
}

export function getRemediationCompletionBonus() {
  return 20
}

/* =========================
   UTILS
========================= */

function shuffle(arr) {
  return [...arr].sort(() => Math.random() - 0.5)
}
